import React, { useState } from "react";

function App() {
  const [name, setName] = useState("");

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!name) {
      alert("Please enter your name");
      return;
    }

    const response = await fetch("http://localhost:5000/generate-certificate", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name }),
    });

    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${name}-certificate.pdf`;
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 to-indigo-100 px-4 py-8">
      <div className="bg-white rounded-2xl shadow-xl p-8 sm:p-10 w-full max-w-md sm:max-w-lg md:max-w-xl text-center">
        <h1 className="text-3xl sm:text-4xl font-bold text-indigo-800 mb-4">
          🎓 Certificate Generator
        </h1>
        <p className="text-gray-600 mb-6 text-sm sm:text-base px-2 sm:px-6">
          Enter your name below to generate your custom certificate.
        </p>

        <form
          onSubmit={handleGenerate}
          className="flex flex-col items-center space-y-4"
        >
          <input
            type="text"
            placeholder="Enter your name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full sm:w-[300px] px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-300"
          />
          <button
            type="submit"
            className="px-6 py-2 bg-indigo-600 text-white rounded-md hover:bg-indigo-700 transition"
          >
            Generate Certificate
          </button>
        </form>
      </div>
    </div>
  );
}

export default App;
